SELECT usage_date AS date, SUM(request_count) AS calls, SUM(prompt_tokens) AS prompt_tokens, SUM(completion_tokens) AS completion_tokens, SUM(total_tokens) AS total_tokens, SUM(total_cost) AS cost
FROM llm_usage_daily WHERE usage_date BETWEEN #{fromDate} AND #{toDate}
GROUP BY usage_date ORDER BY usage_date DESC

SELECT model, SUM(request_count) AS calls, SUM(prompt_tokens) AS prompt_tokens, SUM(completion_tokens) AS completion_tokens, SUM(total_tokens) AS total_tokens, SUM(total_cost) AS cost
FROM llm_usage_daily WHERE usage_date BETWEEN #{fromDate} AND #{toDate}
GROUP BY model ORDER BY total_tokens DESC
